#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string printLCS(string A, string B) {
        int m = A.size(), n = B.size();
        vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (A[i - 1] == B[j - 1])
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                else
                    dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
            }
        }
        string lcs;
        int i = m, j = n;
        while (i > 0 && j > 0) {
            if (A[i - 1] == B[j - 1]) {
                lcs.push_back(A[i - 1]);
                i--;
                j--;
            } else if (dp[i - 1][j] > dp[i][j - 1])
                i--;
            else
                j--;
        }
        reverse(lcs.begin(), lcs.end());
        return lcs;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m, n;
    cin >> m >> n;
    string A, B;
    cin >> A >> B;
    Solution sol;
    cout << sol.printLCS(A, B) << '\n';
    return 0;
}
